// Lê o corpo do POST e valida o índice do anúncio.
const src = $input.first().json;
const b = src.body || src;
const indice = b.anuncio_indice || b.indice;
if (!indice) { throw new Error('Campo "anuncio_indice" é obrigatório.'); }
return [{ json: {
  p_anuncio_indice: String(indice),
  p_user_id: b.user_id || null,
  foco: b.foco ? String(b.foco) : null
} }];

// Extrai e valida o array JSON devolvido pela IA.
const raw = String($input.first().json.text || '').trim();
let jsonStr = raw;
const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
if (fence) jsonStr = fence[1].trim();
const start = jsonStr.indexOf('[');
const end = jsonStr.lastIndexOf(']');
if (start >= 0 && end > start) jsonStr = jsonStr.slice(start, end + 1);
let arr = [];
try { arr = JSON.parse(jsonStr); } catch (e) { arr = []; }
const meta = $('Montar Prompt').first().json;
const VALID = ['acos','roas','conversao','ctr','lucro','saude','receita','ticket_medio'];
function n2(v) { const n = Number(v); return isFinite(n) ? Math.round(n * 100) / 100 : 0; }
const rows = (Array.isArray(arr) ? arr : []).map(function (r, i) {
  let texto = String(r.texto || r.recomendacao || '').trim();
  const econ = n2(r.economia_estimada_reais);
  const ret = n2(r.retorno_estimado_reais);
  // Garante que o impacto em R$ apareça no texto (exigência do negócio).
  if (!/R\$\s*\d/.test(texto) && (econ > 0 || ret > 0)) {
    const partes = [];
    if (econ > 0) partes.push('economiza ~R$ ' + econ.toLocaleString('pt-BR'));
    if (ret > 0) partes.push('rende +R$ ' + ret.toLocaleString('pt-BR'));
    texto += ' 💰 Impacto: ' + partes.join(' · ') + '.';
  }
  return {
    anuncio_indice: meta.p_anuncio_indice,
    loja: r.loja || meta.loja || null,
    produto: r.produto || meta.produto || null,
    texto: texto,
    prioridade: Number(r.prioridade) || (i + 1),
    metrica_alvo: VALID.indexOf(String(r.metrica_alvo)) >= 0 ? r.metrica_alvo : null
  };
}).filter(function (r) { return r.texto.length > 5; });
if (rows.length === 0) { throw new Error('A IA não retornou recomendações válidas.'); }
return [{ json: { p_user_id: meta.p_user_id || null, p_rows: rows } }];
